import{_ as r,o as t,c as n,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G05: 營收模式與收費策略","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G05_營收模式與收費策略_產品經理.md","filePath":"32Ｑ題本＿重要/經營組/G05_營收模式與收費策略_產品經理.md"}'),l={name:"32Ｑ題本＿重要/經營組/G05_營收模式與收費策略_產品經理.md"};function i(a,o,s,g,c,d){return t(),n("div",null,[...o[0]||(o[0]=[e('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="g05-營收模式與收費策略" tabindex="-1">G05: 營收模式與收費策略 <a class="header-anchor" href="#g05-營收模式與收費策略" aria-label="Permalink to &quot;G05: 營收模式與收費策略&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G05</li><li><strong>題目：</strong> 公司的主要營收模式與收費策略為何？其獲利的穩定性與可預測性如何？</li><li><strong>推薦專家：</strong> 產品經理 (<code>product-manager</code>)</li><li><strong>推薦理由：</strong> 專精於「獲利地圖實測」與「商業計畫評估」。擅長拆解企業的現金流產生邏輯，能從收費頻率（一次性 vs 訂閱制）中預判其業績防禦力，並識別出隱藏的「價格侵蝕」風險。</li><li><strong>意圖：</strong> 執行「商業模式穩定性與毛利韌性審計」。判定公司是否具備「長期穩定收費」的能力，識別營收分佈的週期性與脆弱點，預警因「一次性專案」比例過高而導致的業績暴漲暴跌風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockRevenue</code> 分析月營收變動率 (MoM) 與標準差，觀察營收的「季節性特徵」。</li><li><strong>【業務邏輯拆解：Annual Report (年報)】</strong>：進入 <code>業務概況 -&gt; 營收來源類別</code>。提取「勞務收入」、「產品銷售」與「權利金」之百分比。</li><li><strong>【穿透校準：財報附註】</strong>：核實「收入認列政策」，判定是否存在「提前塞貨 (Channel Stuffing)」之財務粉飾空間。</li><li><strong>【外部事實確認：官網定價頁 (Pricing Page)】</strong>：直接觀察其商業版與企業版收費標準，判定其是否具備「客戶黏著度」。</li></ol></li><li><strong>邏輯：</strong> 執行「獲利週期算則」——分析營收年增率 (YoY) 對比現金流量表之「收入質量比」；執行「轉換成本壓力測試」——判定客戶在收費調漲時的流失概率。</li><li><strong>來源：</strong> <code>FinMind (月營收與波動率)</code>, <code>年度報告 (業務明細)</code>, <code>公司官方產品定價表</code>, <code>法人說明會 (營收指引)</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【收費性質事實優先】</strong>：智慧體<strong>必須</strong>明確標註營收屬「一次性買斷」還是「持續性服務」。若持續性（Recurring Revenue）佔比低於 40%，必須發出「業績能見度低」之警示。</li><li><strong>【價格傳導力審核】</strong>：分析當「原材料」或「薪資」上漲時，公司是否具備將成本轉嫁給客戶的「定價權」。禁止在未分析毛利走勢前 general 認定其「具備產品力」。</li><li><strong>【單一合約風險】</strong>：識別是否存在「單一重大合約」佔年營收超過 15% 以上之情境。若有，必須標註其為「營收集中度風險」。</li><li><strong>【描述指標】</strong>：絕對禁用「獲利穩健」、「市場接受」。必須量化為具體的「經常性收益佔比 %」、「平均合約期間」與「ARPU (每用戶平均收入) 趨勢」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g05-專家答詢】產品經理-product-manager" tabindex="-1">【G05 專家答詢】產品經理 (product-manager) <a class="header-anchor" href="#【g05-專家答詢】產品經理-product-manager" aria-label="Permalink to &quot;【G05 專家答詢】產品經理 (product-manager)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「營收結構+穩定性判定」結構（例：營收以 [訂閱/專案] 為主，穩定性 [高/低]，獲利具備 [強/弱] 防禦能力，長期成長動能取決於 [新客獲取/舊客黏著] ）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：經常性收益佔比 &gt; 70%，客戶轉換成本極高，具備強大的價格傳導力，業績極其可預測。</li><li><strong>A (良)</strong>：獲利模式穩定，具備產業代表性，營收雖有季節性波動但長期趨勢向上。</li><li><strong>B (持平)</strong>：高度依賴專案性收入，收費策略頻繁更動，且毛利率受客戶壓價影響顯著，業績可預測性極低。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>revenue</code> 波動數據、年報 P.XXX 營收組合比例。</li><li><strong>【專家建議】注意事項</strong>：建議投資人關注「客戶流失率 (Churn Rate)」是否因競爭對手低價策略而正在攀升。</li></ul>',9)])])}const h=r(l,[["render",i]]);export{u as __pageData,h as default};
